<div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3">Service Packages</h1><p class="text-muted mb-0">Bundle services into clear customer-facing packages.</p></div><button class="btn btn-primary" data-bs-toggle="modal" data-bs-target="#packageModal"><i class="fa-solid fa-plus me-2"></i>New Package</button></div>
<div class="row g-3"><?php foreach($packages as $p): ?><div class="col-lg-4"><div class="card h-100"><div class="card-body"><h2 class="h5"><?= e($p['name']) ?></h2><div class="display-6 fw-bold mb-3"><?= money($p['package_price']) ?></div><p><?= e($p['description']??'') ?></p><ul><?php foreach($packageItems[$p['id']]??[] as $i): ?><li><?= e($i['service_name']) ?></li><?php endforeach ?></ul></div></div></div><?php endforeach ?></div>
